import * as Y from 'yjs';
import { ExperimentCRDT } from './ExperimentCRDT.js';
import type { UserPresence } from './types.js';

export type PresenceCallback = (users: UserPresence[]) => void;

/**
 * PresenceManager handles user presence and awareness features
 * for collaborative editing sessions.
 */
export class PresenceManager {
  private awareness: Y.Awareness;
  private presenceCallbacks: Set<PresenceCallback> = new Set();
  private inactivityTimeout = 30000; // 30 seconds
  private inactivityTimers: Map<number, NodeJS.Timeout> = new Map();

  constructor(private crdt: ExperimentCRDT) {
    const awareness = crdt.getAwareness();
    if (!awareness) {
      throw new Error('CRDT must be initialized with awareness enabled for presence features');
    }

    this.awareness = awareness;
    this.setupPresenceHandlers();
  }

  /**
   * Set local user information
   */
  setLocalUser(user: Partial<UserPresence>): void {
    const currentState = this.awareness.getLocalState() || {};

    this.awareness.setLocalState({
      ...currentState,
      user: {
        ...currentState.user,
        ...user,
        lastActivity: Date.now(),
        isActive: true
      }
    });
  }

  /**
   * Update local user cursor position
   */
  updateCursor(line: number, column: number): void {
    const currentState = this.awareness.getLocalState() || {};

    this.awareness.setLocalState({
      ...currentState,
      user: {
        ...currentState.user,
        cursor: { line, column },
        lastActivity: Date.now(),
        isActive: true
      }
    });

    this.resetInactivityTimer(this.awareness.clientID);
  }

  /**
   * Update local user selection
   */
  updateSelection(elementId: string, elementType: UserPresence['selection']['elementType']): void {
    const currentState = this.awareness.getLocalState() || {};

    this.awareness.setLocalState({
      ...currentState,
      user: {
        ...currentState.user,
        selection: { elementId, elementType },
        lastActivity: Date.now(),
        isActive: true
      }
    });

    this.resetInactivityTimer(this.awareness.clientID);
  }

  /**
   * Clear local user selection
   */
  clearSelection(): void {
    const currentState = this.awareness.getLocalState() || {};

    this.awareness.setLocalState({
      ...currentState,
      user: {
        ...currentState.user,
        selection: undefined,
        lastActivity: Date.now(),
        isActive: true
      }
    });
  }

  /**
   * Subscribe to presence changes
   */
  onPresenceChange(callback: PresenceCallback): () => void {
    this.presenceCallbacks.add(callback);

    // Send initial state
    callback(this.getActiveUsers());

    return () => {
      this.presenceCallbacks.delete(callback);
    };
  }

  /**
   * Get all active users
   */
  getActiveUsers(): UserPresence[] {
    const users: UserPresence[] = [];

    this.awareness.getStates().forEach((state, clientId) => {
      if (state.user && clientId !== this.awareness.clientID) {
        users.push({
          ...state.user,
          userId: state.user.userId || `user-${clientId}`
        });
      }
    });

    // Include local user
    const localState = this.awareness.getLocalState();
    if (localState?.user) {
      users.push({
        ...localState.user,
        userId: localState.user.userId || `user-${this.awareness.clientID}`
      });
    }

    return users.filter(user => user.isActive);
  }

  /**
   * Get user by ID
   */
  getUserById(userId: string): UserPresence | null {
    const users = this.getActiveUsers();
    return users.find(u => u.userId === userId) || null;
  }

  /**
   * Clean up resources
   */
  destroy(): void {
    // Clear all timers
    this.inactivityTimers.forEach(timer => clearTimeout(timer));
    this.inactivityTimers.clear();

    // Clear callbacks
    this.presenceCallbacks.clear();

    // Clear local state
    this.awareness.setLocalState(null);
  }

  /**
   * Set up awareness event handlers
   */
  private setupPresenceHandlers(): void {
    // Handle awareness updates
    this.awareness.on('update', ({ added, updated, removed }: any) => {
      const changes = [...added, ...updated, ...removed];

      if (changes.length > 0) {
        // Update activity timers
        [...added, ...updated].forEach(clientId => {
          this.resetInactivityTimer(clientId);
        });

        // Clear timers for removed clients
        removed.forEach((clientId: number) => {
          const timer = this.inactivityTimers.get(clientId);
          if (timer) {
            clearTimeout(timer);
            this.inactivityTimers.delete(clientId);
          }
        });

        // Notify callbacks
        this.notifyPresenceChange();
      }
    });

    // Handle local state changes
    this.awareness.on('change', () => {
      this.notifyPresenceChange();
    });
  }

  /**
   * Reset inactivity timer for a client
   */
  private resetInactivityTimer(clientId: number): void {
    // Clear existing timer
    const existingTimer = this.inactivityTimers.get(clientId);
    if (existingTimer) {
      clearTimeout(existingTimer);
    }

    // Set new timer
    const timer = setTimeout(() => {
      this.markUserInactive(clientId);
    }, this.inactivityTimeout);

    this.inactivityTimers.set(clientId, timer);
  }

  /**
   * Mark a user as inactive
   */
  private markUserInactive(clientId: number): void {
    if (clientId === this.awareness.clientID) {
      // Mark local user as inactive
      const currentState = this.awareness.getLocalState() || {};
      this.awareness.setLocalState({
        ...currentState,
        user: {
          ...currentState.user,
          isActive: false
        }
      });
    }

    // Remove timer
    this.inactivityTimers.delete(clientId);

    // Notify callbacks
    this.notifyPresenceChange();
  }

  /**
   * Notify all callbacks of presence changes
   */
  private notifyPresenceChange(): void {
    const users = this.getActiveUsers();
    this.presenceCallbacks.forEach(callback => {
      callback(users);
    });
  }

  /**
   * Get presence indicators for UI rendering
   */
  getPresenceIndicators(): {
    cursors: Array<{ userId: string; position: { line: number; column: number }; color: string }>;
    selections: Array<{ userId: string; elementId: string; color: string }>;
  } {
    const users = this.getActiveUsers();

    return {
      cursors: users
        .filter(u => u.cursor)
        .map(u => ({
          userId: u.userId,
          position: u.cursor!,
          color: u.color
        })),
      selections: users
        .filter(u => u.selection)
        .map(u => ({
          userId: u.userId,
          elementId: u.selection!.elementId,
          color: u.color
        }))
    };
  }
}

