  preference?: 'local' | 'remote' | 'newer' | 'merge';
  customResolver?: (conflict: ConflictInfo) => any;
}

export interface ConflictResolutionResult {
  resolved: boolean;
  value: any;
  strategy: string;
  confidence: number;
