   */
  registerStrategy(pathPattern: string, strategy: ConflictResolutionStrategy): void {
    this.strategies.set(pathPattern, strategy);
  }

  /**
   * Resolve a conflict based on registered strategies
   */
  resolveConflict(conflict: ConflictInfo): ConflictResolutionResult {
    // Track conflict for analysis
    this.conflictHistory.push(conflict);

    // Try automatic resolution first
    if (conflict.autoResolvable) {
      const autoResult = this.tryAutomaticResolution(conflict);
      if (autoResult.resolved) {
        return autoResult;
      }
    }

    // Find matching strategy
    const strategy = this.findMatchingStrategy(conflict.path);

    if (strategy) {
      return this.applyStrategy(conflict, strategy);
    }

    // Default resolution
    return this.defaultResolution(conflict);
  }

  /**
   * Get conflict history for analysis
   */
  getConflictHistory(): ConflictInfo[] {
    return [...this.conflictHistory];
  }

  /**
   * Clear conflict history
   */
  clearHistory(): void {
    this.conflictHistory = [];
  }

  /**
   * Analyze conflict patterns
   */
  analyzeConflictPatterns(): {
    totalConflicts: number;
    byType: Record<string, number>;
    byPath: Record<string, number>;
    resolutionSuccess: number;
  } {
    const analysis = {
      totalConflicts: this.conflictHistory.length,
      byType: {} as Record<string, number>,
      byPath: {} as Record<string, number>,
      resolutionSuccess: 0
    };

    this.conflictHistory.forEach(conflict => {
      // Count by type
      analysis.byType[conflict.type] = (analysis.byType[conflict.type] || 0) + 1;

      // Count by path
      const pathKey = conflict.path.join('.');
      analysis.byPath[pathKey] = (analysis.byPath[pathKey] || 0) + 1;

      // Count successful resolutions
      if (conflict.autoResolvable) {
        analysis.resolutionSuccess++;
      }
    });

    return analysis;
  }

  /**
   * Set up default resolution strategies
   */
  private setupDefaultStrategies(): void {
    // Timing conflicts - prefer more conservative (longer) timing
    this.registerStrategy('*.duration', {
