/**
 * Optimize large experiment data structures
 */
optimizeLargeExperiment(experiment: any): any {
  if (!this.options.enableDeltaCompression) {
    return experiment;
  }

  const dataSize = JSON.stringify(experiment).length;

  if (dataSize < (this.options.compressionThreshold || 1024)) {
    return experiment;
  }

  // Apply optimizations
  const optimized = this.compressExperimentData(experiment);

  // Update compression metrics
  const compressedSize = JSON.stringify(optimized).length;
  this.metrics.compressionRatio = dataSize / compressedSize;

  return optimized;
}

