import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { ExperimentCRDT } from '../src/ExperimentCRDT';
import { PresenceManager } from '../src/PresenceManager';
import type { UserPresence } from '../src/types';

describe('PresenceManager', () => {
  let crdt: ExperimentCRDT;
  let presenceManager: PresenceManager;

  beforeEach(() => {
    // Create CRDT with awareness
    crdt = new ExperimentCRDT('test-experiment', {
      awareness: true,
      enableWebRTC: false,
      enableWebSocket: false,
      enableIndexedDB: false
    });

    presenceManager = new PresenceManager(crdt);
  });

  afterEach(() => {
    presenceManager?.destroy();
    crdt?.destroy();
  });

  describe('initialization', () => {
    it('should create presence manager', () => {
      expect(presenceManager).toBeDefined();
    });

    it('should throw error if CRDT has no awareness', () => {
      const crdtNoAwareness = new ExperimentCRDT('test', {
        awareness: false,
        enableWebRTC: false,
        enableWebSocket: false,
        enableIndexedDB: false
      });

      expect(() => new PresenceManager(crdtNoAwareness)).toThrow();
      crdtNoAwareness.destroy();
    });
  });

  describe('local user management', () => {
    it('should set local user information', () => {
      const userInfo: Partial<UserPresence> = {
        userId: 'user-123',
        userName: 'Test User',
        color: '#3B82F6'
      };

      presenceManager.setLocalUser(userInfo);

      const users = presenceManager.getActiveUsers();
      const localUser = users.find(u => u.userId === 'user-123');

      expect(localUser).toBeDefined();
      expect(localUser?.userName).toBe('Test User');
      expect(localUser?.color).toBe('#3B82F6');
      expect(localUser?.isActive).toBe(true);
    });

    it('should update cursor position', () => {
      presenceManager.setLocalUser({ userId: 'user-123' });
      presenceManager.updateCursor(10, 5);

      const users = presenceManager.getActiveUsers();
      const localUser = users.find(u => u.userId === 'user-123');

      expect(localUser?.cursor).toEqual({ line: 10, column: 5 });
    });

    it('should update selection', () => {
      presenceManager.setLocalUser({ userId: 'user-123' });
      presenceManager.updateSelection('trial-1', 'trial');

      const users = presenceManager.getActiveUsers();
      const localUser = users.find(u => u.userId === 'user-123');

      expect(localUser?.selection).toEqual({ 
        elementId: 'trial-1', 
        elementType: 'trial' 
      });
    });

    it('should clear selection', () => {
      presenceManager.setLocalUser({ userId: 'user-123' });
      presenceManager.updateSelection('trial-1', 'trial');
      presenceManager.clearSelection();

      const users = presenceManager.getActiveUsers();
      const localUser = users.find(u => u.userId === 'user-123');

      expect(localUser?.selection).toBeUndefined();
    });
  });

  describe('presence subscriptions', () => {
    it('should subscribe to presence changes', () => {
      const callback = vi.fn();
      const unsubscribe = presenceManager.onPresenceChange(callback);

      // Should call immediately with current state
      expect(callback).toHaveBeenCalledWith(expect.any(Array));

      // Update presence
      presenceManager.setLocalUser({ 
        userId: 'user-123',
        userName: 'Test User'
      });

      // Should call callback again
      expect(callback).toHaveBeenCalledTimes(2);

      // Unsubscribe
      unsubscribe();
      callback.mockClear();

      // Update again
      presenceManager.updateCursor(5, 10);

      // Should not call callback
      expect(callback).not.toHaveBeenCalled();
    });
  });

  describe('user retrieval', () => {
    it('should get all active users', () => {
      presenceManager.setLocalUser({
        userId: 'user-123',
        userName: 'User 1',
        color: '#FF0000',
        isActive: true
      });

      const users = presenceManager.getActiveUsers();
      expect(users).toHaveLength(1);
      expect(users[0].userId).toBe('user-123');
    });

    it('should get user by ID', () => {
      presenceManager.setLocalUser({
        userId: 'user-123',
        userName: 'Test User'
      });

      const user = presenceManager.getUserById('user-123');
      expect(user).toBeDefined();
      expect(user?.userName).toBe('Test User');

      const nonExistent = presenceManager.getUserById('user-999');
      expect(nonExistent).toBeNull();
    });
  });

  describe('presence indicators', () => {
    it('should get cursor indicators', () => {
      presenceManager.setLocalUser({
        userId: 'user-123',
        userName: 'User 1',
        color: '#FF0000'
      });
      presenceManager.updateCursor(10, 5);

      const indicators = presenceManager.getPresenceIndicators();

      expect(indicators.cursors).toHaveLength(1);
      expect(indicators.cursors[0]).toEqual({
        userId: 'user-123',
        position: { line: 10, column: 5 },
        color: '#FF0000'
      });
    });

    it('should get selection indicators', () => {
      presenceManager.setLocalUser({
        userId: 'user-123',
        userName: 'User 1',
        color: '#00FF00'
      });
      presenceManager.updateSelection('element-1', 'stimulus');

      const indicators = presenceManager.getPresenceIndicators();

      expect(indicators.selections).toHaveLength(1);
      expect(indicators.selections[0]).toEqual({
        userId: 'user-123',
        elementId: 'element-1',
        color: '#00FF00'
      });
    });
  });

  describe('cleanup', () => {
    it('should clear state on destroy', () => {
      const callback = vi.fn();
      presenceManager.onPresenceChange(callback);

      presenceManager.setLocalUser({ userId: 'user-123' });
      presenceManager.destroy();

      // Awareness should be cleared
      const awareness = crdt.getAwareness();
      expect(awareness?.getLocalState()).toBeNull();
    });
  });
});

