## ExperimentCRDT.ts (Core CRDT Management)
```typescript
import * as Y from 'yjs';
import { WebrtcProvider } from 'y-webrtc';
import { WebsocketProvider } from 'y-websocket';
import { IndexeddbPersistence } from 'y-indexeddb';
import { Awareness } from 'y-protocols/awareness';
import type { CompiledExperiment, ForgeScriptAST } from '@psyforge/forgescript';

export class ExperimentCRDT {
  private doc: Y.Doc;
  private experimentMap: Y.Map<any>;
  private providers: Array<WebrtcProvider | WebsocketProvider | IndexeddbPersistence> = [];
  private awareness?: Awareness;

  constructor(experimentId: string, options: CRDTOptions = {}) {
    this.doc = new Y.Doc();
    this.experimentMap = this.doc.getMap('experiment');

    if (awareness) {
      this.awareness = new Awareness(this.doc);
    }

    // Initialize providers
    if (enableWebRTC) {
      const webrtcProvider = new WebrtcProvider(experimentId, this.doc, {
        signaling: [websocketUrl],
        awareness: this.awareness
      });
      this.providers.push(webrtcProvider);
    }
    // Similar for WebSocket and IndexedDB...
  }

  // Methods for updates, subscriptions, etc.
}
```

## VisualCodeBinding.ts (Bidirectional Sync)
```typescript
export class VisualCodeBinding {
  private updateQueued = false;
  private visualUpdateDebouncer?: NodeJS.Timeout;
  private codeUpdateDebouncer?: NodeJS.Timeout;

  setupVisualToCodeBinding(): void {
    this.crdt.onExperimentChange((changes) => {
      if (this.updateQueued) return;

      clearTimeout(this.visualUpdateDebouncer);
      this.visualUpdateDebouncer = setTimeout(() => {
        this.updateVisualFromChanges(changes);
        this.updateQueued = false;
      }, 50);
    });
  }

  private updateCodeFromVisual(event: VisualChangeEvent): void {
    this.updateQueued = true;
    const ast = this.generateASTFromVisual(event);
    this.crdt.updateFromCode(ast);

    clearTimeout(this.codeUpdateDebouncer);
    this.codeUpdateDebouncer = setTimeout(() => {
      const code = this.generateCodeFromAST(ast);
      this.updateMonacoEditor(code);
    }, 100);
  }
}
```

## ConflictResolution.ts (Merge Handling)
```typescript
export class ConflictResolution {
  private strategies: Map<string, ConflictResolutionStrategy> = new Map();

  resolveConflict(conflict: ConflictInfo): ConflictResolutionResult {
    this.conflictHistory.push(conflict);

    if (conflict.autoResolvable) {
      const autoResult = this.tryAutomaticResolution(conflict);
      if (autoResult.resolved) return autoResult;
    }

    const strategy = this.findMatchingStrategy(conflict.path);
    if (strategy) {
      return this.applyStrategy(conflict, strategy);
    }

    return this.defaultResolution(conflict);
  }

  private matchesPattern(path: string, pattern: string): boolean {
    const regexPattern = pattern
      .replace(/\./g, '\\.')
      .replace(/\*\*/g, '__DOUBLE_STAR__')
      .replace(/\*/g, '[^.]+')
      .replace(/__DOUBLE_STAR__/g, '.*');

    return new RegExp(`^${regexPattern}$`).test(path);
  }
}
```

## GUI Integration (CollaborationIndicator.svelte)
```svelte
<script lang="ts">
  import { onMount, onDestroy } from 'svelte';
  import { collaborationStore } from '$lib/stores/collaboration';

  let connectionStatus = 'disconnected';
  let activeUsers: UserPresence[] = [];
  let syncStatus = 'idle';

  onMount(() => {
    const unsubscribe = collaborationStore.subscribe(state => {
      connectionStatus = state.connectionStatus;
      activeUsers = state.activeUsers;
      syncStatus = state.syncStatus;
    });
    return unsubscribe;
  });
</script>

<div class="collaboration-indicator">
  <ConnectionDot status={connectionStatus} />
  <UserList users={activeUsers} />
  <SyncIndicator status={syncStatus} />
</div>
```

